// src/pages/intern/index.jsx  –  All intern pages
import { useState, useEffect, useCallback } from "react";
import { taskAPI, userAPI } from "../../utils/api";
import { StatusBadge, Avatar, Toast } from "../../components/shared/index.jsx";
import TaskModal from "../../components/shared/TaskModal.jsx";
import { computeStats, formatMinutes, statusSelectClass } from "../../utils/helpers";
import { useAuth } from "../../hooks/useAuth";

// ── INTERN DASHBOARD ──────────────────────────────────────────────────────────
export function InternDashboard() {
  const { user }  = useAuth();
  const [tasks,   setTasks]   = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    taskAPI.getAll()
      .then(d => { setTasks(d.tasks || []); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const { total, done, inProgress, hold, todo, totalMins } = computeStats(tasks);
  const weekMins = tasks.slice(-10).reduce((s, t) => s + (parseInt(t.totalMinutes) || 0), 0);
  const reqMins  = 30 * 60;
  const weekPct  = Math.min(100, Math.round((weekMins / reqMins) * 100));

  if (loading) return <div style={{ padding:60, textAlign:"center" }}><div className="spinner" style={{ margin:"0 auto" }}/></div>;

  return (
    <div className="animate-fadeUp">
      <div className="alert alert-warning mb-20">
        ⚡ The internship requires at least <strong>&nbsp;6 hours/day</strong>, amounting to <strong>&nbsp;30 hours/week</strong>.
      </div>

      {/* Stat cards */}
      <div className="grid-4 mb-24">
        {[
          ["✅","Done",        done,       "stat-green","up",     "↑ Keep it up!"],
          ["⚡","In Progress", inProgress, "stat-blue", "neutral","Active"],
          ["⏸","On Hold",     hold,       "stat-gold", "warn",   "Needs action"],
          ["📋","To Do",       todo,       "stat-red",  "neutral","Pending"],
        ].map(([icon, label, val, cls, chg, chgTxt]) => (
          <div key={label} className={`stat-card ${cls}`}>
            <div className="stat-icon">{icon}</div>
            <div className="stat-value">{val}</div>
            <div className="stat-label">{label}</div>
            <div className={`stat-change ${chg}`}>{chgTxt}</div>
          </div>
        ))}
      </div>

      <div className="grid-2 mb-24">
        {/* Weekly hours */}
        <div className="card">
          <div className="card-header">
            <div className="card-title">⏱ Weekly Hours</div>
            <span className="badge" style={{ background: weekPct >= 100 ? "#dcfce7" : "#fef3c7", color: weekPct >= 100 ? "#166534" : "#92400e" }}>{weekPct}%</span>
          </div>
          <div className="card-body">
            <div className="flex justify-between mb-8">
              <span className="text-sm text-gray">Progress</span>
              <span className="text-sm text-bold">{formatMinutes(weekMins)} / 30h</span>
            </div>
            <div className="progress-bar">
              <div className={`progress-fill${weekPct < 50 ? " danger" : weekPct < 80 ? " warn" : ""}`} style={{ width: weekPct + "%" }}/>
            </div>
            <p style={{ marginTop:8, fontSize:12, fontWeight:600, color: weekPct >= 100 ? "var(--green-500)" : "var(--orange)" }}>
              {weekPct >= 100 ? "✅ Weekly target met!" : `${100 - weekPct}% remaining`}
            </p>
            <div className="divider"/>
            <div className="flex justify-between">
              <div>
                <div className="text-xs text-gray uppercase">All-time logged</div>
                <div style={{ fontFamily:"Syne,sans-serif", fontSize:24, fontWeight:800, color:"var(--green-900)", marginTop:4 }}>{formatMinutes(totalMins)}</div>
              </div>
              <div style={{ textAlign:"right" }}>
                <div className="text-xs text-gray uppercase">Total tasks</div>
                <div style={{ fontFamily:"Syne,sans-serif", fontSize:24, fontWeight:800, color:"var(--green-900)", marginTop:4 }}>{total}</div>
              </div>
            </div>
          </div>
        </div>

        {/* Task breakdown */}
        <div className="card">
          <div className="card-header"><div className="card-title">📊 Breakdown</div></div>
          <div className="card-body">
            {[["Done",done,"#16a34a"],["In Progress",inProgress,"#1d4ed8"],["To Do",todo,"#6b7280"],["Hold",hold,"#d97706"]].map(([l, v, c]) => (
              <div key={l} className="flex items-center gap-10 mb-16">
                <div style={{ width:10, height:10, borderRadius:"50%", background:c, flexShrink:0 }}/>
                <div style={{ flex:1, fontSize:13 }}>{l}</div>
                <div style={{ fontSize:13, fontWeight:700, minWidth:24, textAlign:"right" }}>{v}</div>
                <div style={{ width:90, height:6, background:"var(--gray-100)", borderRadius:3, overflow:"hidden" }}>
                  <div style={{ height:"100%", width: total ? (v / total * 100) + "%" : "0%", background:c, borderRadius:3 }}/>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Recent tasks */}
      <div className="card">
        <div className="card-header"><div className="card-title">🕐 Recent Tasks</div></div>
        <div className="table-wrap">
          {tasks.length === 0 ? (
            <div className="empty-state"><div className="empty-icon">📭</div><h3>No tasks yet</h3></div>
          ) : (
            <table>
              <thead><tr><th>Date</th><th>Project</th><th>Task</th><th>Status</th><th>Time</th><th>Mins</th></tr></thead>
              <tbody>
                {tasks.slice(0, 8).map(t => (
                  <tr key={t.id}>
                    <td className="text-sm text-gray">{t.date}</td>
                    <td><span className="tag">{t.project}</span></td>
                    <td className="text-sm" style={{ maxWidth:240 }}>{t.task}</td>
                    <td><StatusBadge status={t.status}/></td>
                    <td className="text-sm text-gray">{t.timeFrom} → {t.timeTo}</td>
                    <td className="text-sm text-bold">{t.totalMinutes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}

// ── MY TASKS PAGE ─────────────────────────────────────────────────────────────
export function MyTasksPage() {
  const { user }    = useAuth();
  const [tasks,     setTasks]     = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [saving,    setSaving]    = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editTask,  setEditTask]  = useState(null);
  const [toast,     setToast]     = useState(null);
  const [status,    setStatus]    = useState("All");
  const [search,    setSearch]    = useState("");

  const load = useCallback(() => {
    setLoading(true);
    taskAPI.getAll({ status: status !== "All" ? status : undefined, search: search || undefined })
      .then(d => { setTasks(d.tasks || []); setLoading(false); })
      .catch(() => setLoading(false));
  }, [status, search]);

  useEffect(() => { load(); }, [load]);

  const handleSave = async (form) => {
    setSaving(true);
    try {
      if (editTask) {
        const d = await taskAPI.update(editTask.id, form);
        setTasks(ts => ts.map(t => t.id === editTask.id ? d.task : t));
        setToast({ msg:"Task updated!", type:"success" });
      } else {
        const d = await taskAPI.create({ ...form, assignedTo: user.id });
        setTasks(ts => [d.task, ...ts]);
        setToast({ msg:"Task created!", type:"success" });
      }
      setShowModal(false); setEditTask(null);
    } catch (e) { setToast({ msg: e.message, type:"error" }); }
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this task?")) return;
    try {
      await taskAPI.delete(id);
      setTasks(ts => ts.filter(t => t.id !== id));
      setToast({ msg:"Task deleted.", type:"success" });
    } catch (e) { setToast({ msg: e.message, type:"error" }); }
  };

  const handleStatus = async (id, newStatus) => {
    try {
      const d = await taskAPI.updateStatus(id, newStatus);
      setTasks(ts => ts.map(t => t.id === id ? d.task : t));
    } catch (e) { setToast({ msg: e.message, type:"error" }); }
  };

  return (
    <div className="animate-fadeUp">
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)}/>}
      {showModal && (
        <TaskModal
          task={editTask}
          currentUser={user}
          onClose={() => { setShowModal(false); setEditTask(null); }}
          onSave={handleSave}
          loading={saving}
        />
      )}

      <div className="card">
        <div className="card-header">
          <div className="card-title">📋 My Tasks</div>
          <button className="btn btn-primary" onClick={() => { setEditTask(null); setShowModal(true); }}>+ New Task</button>
        </div>

        <div style={{ padding:"14px 24px", borderBottom:"1px solid var(--gray-100)" }}>
          <div className="filters">
            <div className="search-wrap">
              <span className="search-icon">🔍</span>
              <input className="search-input" placeholder="Search tasks…" value={search} onChange={e => setSearch(e.target.value)}/>
            </div>
            <select className="filter-select" value={status} onChange={e => setStatus(e.target.value)}>
              <option value="All">All Status</option>
              {["To Do","In Progress","Done","Hold"].map(s => <option key={s}>{s}</option>)}
            </select>
          </div>
        </div>

        <div className="table-wrap">
          {loading ? (
            <div style={{ padding:40, textAlign:"center" }}><div className="spinner" style={{ margin:"0 auto" }}/></div>
          ) : tasks.length === 0 ? (
            <div className="empty-state"><div className="empty-icon">📭</div><h3>No tasks found</h3><p>Create your first task above.</p></div>
          ) : (
            <table>
              <thead>
                <tr><th>Date</th><th>Project</th><th>Assigned By</th><th>Task</th><th>Status</th><th>Estimate</th><th>From</th><th>To</th><th>Mins</th><th>Doc</th><th>Actions</th></tr>
              </thead>
              <tbody>
                {tasks.map(t => (
                  <tr key={t.id}>
                    <td className="text-sm text-gray">{t.date}</td>
                    <td><span className="tag">{t.project}</span></td>
                    <td className="text-sm">{t.assignedBy}</td>
                    <td className="text-sm" style={{ maxWidth:200 }}>{t.task}</td>
                    <td>
                      <select
                        className={`status-select ${statusSelectClass(t.status)}`}
                        value={t.status}
                        onChange={e => handleStatus(t.id, e.target.value)}
                      >
                        {["To Do","In Progress","Done","Hold"].map(s => <option key={s}>{s}</option>)}
                      </select>
                    </td>
                    <td className="text-sm">{t.estimateTime}</td>
                    <td className="text-sm text-gray">{t.timeFrom}</td>
                    <td className="text-sm text-gray">{t.timeTo}</td>
                    <td className="text-sm text-bold">{t.totalMinutes}</td>
                    <td>{t.workDoc ? <a href={t.workDoc} target="_blank" rel="noreferrer" style={{ color:"var(--green-600)", fontSize:17 }}>🔗</a> : "–"}</td>
                    <td>
                      <div className="flex gap-6">
                        <button className="btn btn-secondary btn-sm btn-icon" onClick={() => { setEditTask(t); setShowModal(true); }}>✏️</button>
                        <button className="btn btn-danger btn-sm btn-icon" onClick={() => handleDelete(t.id)}>🗑</button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}

